import java.io.*;

public class SecureCommandExecution {

    public static void main(String[] args) {
        try {
            // Taking user input
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a file name: ");
            String fileName = br.readLine();

            // Building the command securely using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder("cat", fileName);

            // Redirecting error stream to output stream
            processBuilder.redirectErrorStream(true);

            // Executing the command
            Process process = processBuilder.start();

            // Reading and printing the output of the command
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
           e.printStackTrace();
        }
    }
}

